// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"bytes"
	"context"
	"encoding/json"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
)

// TestNewPolicyAuditLogger tests creating a new PolicyAuditLogger
func TestNewPolicyAuditLogger(t *testing.T) {
	logger := logrus.New()
	level := logrus.InfoLevel

	pal := NewPolicyAuditLogger(logger, level)

	require.NotNil(t, pal)
	require.Equal(t, logger, pal.logger)
	require.Equal(t, level, pal.logLevel)
	require.True(t, pal.enabled)
}

// TestSetLogLevel tests setting the log level
func TestSetLogLevel(t *testing.T) {
	logger := logrus.New()
	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel)

	require.Equal(t, logrus.InfoLevel, pal.logLevel)

	pal.SetLogLevel(logrus.DebugLevel)
	require.Equal(t, logrus.DebugLevel, pal.logLevel)

	pal.SetLogLevel(logrus.WarnLevel)
	require.Equal(t, logrus.WarnLevel, pal.logLevel)
}

// TestSetEnabled tests enabling and disabling the audit logger
func TestSetEnabled(t *testing.T) {
	logger := logrus.New()
	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel)

	require.True(t, pal.enabled)

	pal.SetEnabled(false)
	require.False(t, pal.enabled)

	pal.SetEnabled(true)
	require.True(t, pal.enabled)
}

// TestLogDecision tests logging a policy decision
func TestLogDecision(t *testing.T) {
	logger := logrus.New()
	buffer := &bytes.Buffer{}
	logger.SetOutput(buffer)
	logger.SetFormatter(&logrus.JSONFormatter{})
	logger.SetLevel(logrus.InfoLevel)

	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel)

	testID := identity.NumericIdentity(1000)
	policyName := "test-policy"
	verdict := "allow"
	reason := "matched ingress rule"

	pal.LogDecision(testID, policyName, verdict, reason)

	// Verify the log entry was written
	logOutput := buffer.String()
	require.NotEmpty(t, logOutput)

	// Parse the JSON log entry
	var logEntry map[string]interface{}
	err := json.Unmarshal([]byte(logOutput), &logEntry)
	require.NoError(t, err)

	// Verify the log fields are present
	require.Equal(t, float64(testID), logEntry["identity"])
	require.Equal(t, policyName, logEntry[logrus.FieldKeyFile])
}

// TestLogDecisionDisabled tests that logging is skipped when disabled
func TestLogDecisionDisabled(t *testing.T) {
	logger := logrus.New()
	buffer := &bytes.Buffer{}
	logger.SetOutput(buffer)
	logger.SetLevel(logrus.InfoLevel)

	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel)
	pal.SetEnabled(false)

	pal.LogDecision(identity.NumericIdentity(1000), "policy", "allow", "test")

	// No output should be produced when disabled
	require.Empty(t, buffer.String())
}

// TestLogEvaluation tests logging a policy evaluation
func TestLogEvaluation(t *testing.T) {
	logger := logrus.New()
	buffer := &bytes.Buffer{}
	logger.SetOutput(buffer)
	logger.SetFormatter(&logrus.JSONFormatter{})
	logger.SetLevel(logrus.InfoLevel)

	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel)

	ctx := context.Background()
	policyKey := "test-policy-key"

	// Test with nil selector cache
	pal.LogEvaluation(ctx, policyKey, nil, true)

	// Verify the log entry was written
	logOutput := buffer.String()
	require.NotEmpty(t, logOutput)

	// Parse the JSON log entry
	var logEntry map[string]interface{}
	err := json.Unmarshal([]byte(logOutput), &logEntry)
	require.NoError(t, err)

	// Verify the policy key is logged
	require.Equal(t, policyKey, logEntry["policyKey"])
}

// TestLogEvaluationDisabled tests that evaluation logging is skipped when disabled
func TestLogEvaluationDisabled(t *testing.T) {
	logger := logrus.New()
	buffer := &bytes.Buffer{}
	logger.SetOutput(buffer)
	logger.SetLevel(logrus.InfoLevel)

	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel)
	pal.SetEnabled(false)

	ctx := context.Background()
	pal.LogEvaluation(ctx, "policy-key", nil, true)

	// No output should be produced when disabled
	require.Empty(t, buffer.String())
}

// TestPolicyDecisionJSON tests that PolicyDecision marshals correctly to JSON
func TestPolicyDecisionJSON(t *testing.T) {
	decision := PolicyDecision{
		Identity:   identity.NumericIdentity(1000),
		PolicyName: "test-policy",
		Verdict:    "allow",
		Reason:     "matched rule",
	}

	data, err := json.Marshal(decision)
	require.NoError(t, err)

	var decoded PolicyDecision
	err = json.Unmarshal(data, &decoded)
	require.NoError(t, err)

	require.Equal(t, decision, decoded)
}

// TestPolicyEvaluationResultJSON tests that PolicyEvaluationResult marshals correctly
func TestPolicyEvaluationResultJSON(t *testing.T) {
	result := PolicyEvaluationResult{
		PolicyKey:     "test-key",
		Selected:      true,
		NumIdentities: 42,
		Result:        "selected",
	}

	data, err := json.Marshal(result)
	require.NoError(t, err)

	var decoded PolicyEvaluationResult
	err = json.Unmarshal(data, &decoded)
	require.NoError(t, err)

	require.Equal(t, result, decoded)
}

// TestConcurrentLogDecision tests thread-safety of LogDecision
func TestConcurrentLogDecision(t *testing.T) {
	logger := logrus.New()
	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel)

	// Perform concurrent logging operations
	done := make(chan bool, 10)
	for i := 0; i < 10; i++ {
		go func(id int) {
			pal.LogDecision(identity.NumericIdentity(id), "policy", "allow", "test")
			done <- true
		}(i)
	}

	// Wait for all goroutines to complete
	for i := 0; i < 10; i++ {
		<-done
	}
}

// TestConcurrentLogEvaluation tests thread-safety of LogEvaluation
func TestConcurrentLogEvaluation(t *testing.T) {
	logger := logrus.New()
	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel)

	ctx := context.Background()

	// Perform concurrent logging operations
	done := make(chan bool, 10)
	for i := 0; i < 10; i++ {
		go func(id int) {
			pal.LogEvaluation(ctx, "policy-key", nil, true)
			done <- true
		}(i)
	}

	// Wait for all goroutines to complete
	for i := 0; i < 10; i++ {
		<-done
	}
}

// TestEvalResultString tests the evalResultString function
func TestEvalResultString(t *testing.T) {
	require.Equal(t, "selected", evalResultString(true))
	require.Equal(t, "not_selected", evalResultString(false))
}

// TestLogDecisionWithDifferentLevels tests logging at different log levels
func TestLogDecisionWithDifferentLevels(t *testing.T) {
	for _, level := range []logrus.Level{
		logrus.DebugLevel,
		logrus.InfoLevel,
		logrus.WarnLevel,
		logrus.ErrorLevel,
	} {
		t.Run(level.String(), func(t *testing.T) {
			logger := logrus.New()
			buffer := &bytes.Buffer{}
			logger.SetOutput(buffer)
			logger.SetLevel(level)

			pal := NewPolicyAuditLogger(logger, level)

			// Should log if level matches or is more severe
			pal.LogDecision(identity.NumericIdentity(100), "policy", "allow", "test")

			// Verify output
			require.NotEmpty(t, buffer.String())
		})
	}
}

