	logger := logrus.New()
	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel)

	require.True(t, pal.enabled)

	pal.SetEnabled(false)
	require.False(t, pal.enabled)

	pal.SetEnabled(true)
	require.True(t, pal.enabled)
}

// TestLogDecision tests logging a policy decision
func TestLogDecision(t *testing.T) {
	logger := logrus.New()
	buffer := &bytes.Buffer{}
	logger.SetOutput(buffer)
	logger.SetFormatter(&logrus.JSONFormatter{})
	logger.SetLevel(logrus.InfoLevel)

	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel)

	testID := identity.NumericIdentity(1000)
	policyName := "test-policy"
	verdict := "allow"
	reason := "matched ingress rule"

	pal.LogDecision(testID, policyName, verdict, reason)

	// Verify the log entry was written
	logOutput := buffer.String()
	require.NotEmpty(t, logOutput)

	// Parse the JSON log entry
	var logEntry map[string]interface{}
	err := json.Unmarshal([]byte(logOutput), &logEntry)
	require.NoError(t, err)

	// Verify the log fields are present
	require.Equal(t, float64(testID), logEntry["identity"])
	require.Equal(t, policyName, logEntry[logrus.FieldKeyFile])
}

// TestLogDecisionDisabled tests that logging is skipped when disabled
func TestLogDecisionDisabled(t *testing.T) {
	logger := logrus.New()
	buffer := &bytes.Buffer{}
	logger.SetOutput(buffer)
	logger.SetLevel(logrus.InfoLevel)

	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel)
	pal.SetEnabled(false)

	pal.LogDecision(identity.NumericIdentity(1000), "policy", "allow", "test")

	// No output should be produced when disabled
	require.Empty(t, buffer.String())
}

